export function getPromptsByCategory() {
  const map = {};
  for (const p of PROMPTS) {
    if (!map[p.category]) map[p.category] = [];
    map[p.category].push(p);
  }
  return map;
}

export function getPromptById(id) {
  return PROMPTS.find(p => p.id === id);
}
